query:
// Q3a Points d'articulation (GDS)
CALL () {
  CALL gds.graph.drop('wan_bm_ap', false) YIELD graphName
  RETURN count(graphName) AS dropped
}
CALL gds.graph.project('wan_bm_ap', 'Router', {CONNECTED_TO: {orientation: 'UNDIRECTED'}}) YIELD graphName
CALL gds.articulationPoints.stream(graphName) YIELD nodeId
RETURN gds.util.asNode(nodeId).hostname AS spof_router
ORDER BY spof_router

// Q3b Ponts (GDS)
CALL () {
  CALL gds.graph.drop('wan_bm_br', false) YIELD graphName
  RETURN count(graphName) AS dropped
}
CALL gds.graph.project('wan_bm_br', 'Router', {CONNECTED_TO: {orientation: 'UNDIRECTED'}}) YIELD graphName
CALL gds.bridges.stream(graphName) YIELD from, to
RETURN gds.util.asNode(from).hostname AS endpoint_a, gds.util.asNode(to).hostname AS endpoint_b
ORDER BY endpoint_a, endpoint_b

// Q5b Trois routes alternatives (Yen)
CALL () {
  CALL gds.graph.drop('wan_bm_yens', false) YIELD graphName
  RETURN count(graphName) AS dropped
}
CALL gds.graph.project('wan_bm_yens', 'Router', {CONNECTED_TO: {orientation: 'UNDIRECTED', properties: 'latency_ms'}}) YIELD graphName
MATCH (src:Router)-[:LOCATED_IN]->(:City {code: $src})
WITH graphName, src ORDER BY src.hostname LIMIT 1
MATCH (dst:Router)-[:LOCATED_IN]->(:City {code: $dst})
WITH graphName, src, dst ORDER BY dst.hostname LIMIT 1
CALL gds.shortestPath.yens.stream(graphName, {
  sourceNode: src, targetNode: dst, k: 3, relationshipWeightProperty: 'latency_ms'
}) YIELD index, totalCost, nodeIds
RETURN index + 1 AS route, [id IN nodeIds | gds.util.asNode(id).hostname] AS hops,
       totalCost AS total_latency_ms

// Q6c Sous-graphe incident
MATCH p = (i:Incident)-[:AFFECTS]->(:Router)-[:CONNECTED_TO]-(:Router)
RETURN p

// Q6d Reset
MATCH (i:Incident {id: 'INC-2026-0001'}) DETACH DELETE i;
MATCH (r:Router {hostname: 'PAR-CORE-01'}) SET r.status = 'UP';
